css:
.loader {
  display: grid;
  width: 118px;
  gap: 10px;
}
.loader i {
  display: block;
  height: 10px;
  border-radius: 999px;
  background: linear-gradient(90deg, color-mix(in srgb, var(--loader-color) 12%, transparent), color-mix(in srgb, var(--loader-color) 34%, transparent), color-mix(in srgb, var(--loader-color) 12%, transparent));
  background-size: 220% 100%;
  animation: skeletonShimmer 1.1s linear infinite;
}
.loader i:first-child { width: 72px; height: 44px; border-radius: 14px; }
.loader i:nth-child(2) { width: 100%; }
.loader i:nth-child(3) { width: 76%; }
.loader i:nth-child(4) { width: 54%; }
@keyframes skeletonShimmer { to { background-position: -220% 0; } }
